import { useStandaloneTimePicker } from "react-date-range-picker-headless";
import type { TimePickerPanelProps } from "@/lib/types";
import { cn, sizeClass } from "@/lib/utils";
import { TimePanelInternal } from "@/lib/time-panel-internal";

export function TimePickerPanel({
  size,
  className,
  style,
  hideFooter,
  renderFooter,
  ...options
}: TimePickerPanelProps) {
  const picker = useStandaloneTimePicker(options);
  const { locale } = picker;

  const resolvedConfig = {
    precision: options.time?.precision ?? "minute",
    hourFormat: options.time?.hourFormat ?? "24",
    minuteStep: options.time?.minuteStep ?? 5,
    secondStep: options.time?.secondStep ?? 1,
    itemHeight: options.time?.itemHeight ?? 32,
  } as const;

  const footerEl =
    !hideFooter &&
    (renderFooter ? (
      renderFooter({
        canConfirm: true,
        hasValue: picker.hasValue,
        onConfirm: picker.handleConfirm,
        onCancel: picker.handleCancel,
        onClear: picker.handleClear,
        locale,
      })
    ) : (
      <div className="flex justify-end gap-2 mt-4 pt-4 border-t border-border">
        {picker.hasValue && (
          <button
            type="button"
            className="px-3 py-1.5 text-sm text-muted-foreground hover:text-foreground hover:bg-accent rounded-md transition-colors cursor-pointer"
            onClick={picker.handleClear}
          >
            {locale.clear}
          </button>
        )}
        <button
          type="button"
          className="px-3 py-1.5 text-sm text-muted-foreground hover:text-foreground hover:bg-accent rounded-md transition-colors cursor-pointer"
          onClick={picker.handleCancel}
        >
          {locale.cancel}
        </button>
        <button
          type="button"
          className="px-3 py-1.5 text-sm text-primary-foreground bg-primary hover:bg-primary/90 rounded-md transition-colors disabled:opacity-50 disabled:pointer-events-none cursor-pointer"
          onClick={picker.handleConfirm}
        >
          {locale.confirm}
        </button>
      </div>
    ));

  return (
    <div
      className={cn(
        "relative w-max font-sans text-[13px] text-foreground bg-popover border border-border rounded-lg shadow-sm select-none p-4",
        sizeClass(size),
        className,
      )}
      style={style}
    >
      <TimePanelInternal
        hour={picker.tempHour}
        minute={picker.tempMinute}
        second={picker.tempSecond}
        period={picker.tempPeriod}
        onHourChange={picker.handleHourChange}
        onMinuteChange={picker.handleMinuteChange}
        onSecondChange={picker.handleSecondChange}
        onPeriodChange={picker.handlePeriodChange}
        timeConfig={resolvedConfig}
      />
      {footerEl}
    </div>
  );
}

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";
import type { DatePickerSize } from "react-date-range-picker-headless";

/** Merge class names with Tailwind conflict resolution. */
export function cn(...args: ClassValue[]): string {
  return twMerge(clsx(args));
}

/** Return the size modifier class. Uses data-slot attributes for descendant targeting. */
export function sizeClass(size: DatePickerSize = "medium"): string {
  const sizeMap: Record<DatePickerSize, string> = {
    small:
      'text-xs [&_[data-slot="day"]]:w-7 [&_[data-slot="day"]]:h-7 [&_[data-slot="time-item"]]:text-xs [&_[data-slot="time-item"]]:h-6 [&_[data-slot="time-panel"]]:w-48',
    medium:
      'text-sm [&_[data-slot="day"]]:w-9 [&_[data-slot="day"]]:h-9 [&_[data-slot="time-item"]]:text-sm [&_[data-slot="time-item"]]:h-8 [&_[data-slot="time-panel"]]:w-56',
    large:
      'text-base [&_[data-slot="day"]]:w-11 [&_[data-slot="day"]]:h-11 [&_[data-slot="time-item"]]:text-base [&_[data-slot="time-item"]]:h-10 [&_[data-slot="time-panel"]]:w-64',
    "x-large":
      'text-lg [&_[data-slot="day"]]:w-12 [&_[data-slot="day"]]:h-12 [&_[data-slot="time-item"]]:text-lg [&_[data-slot="time-item"]]:h-12 [&_[data-slot="time-panel"]]:w-72',
  };
  return sizeMap[size] || sizeMap["medium"];
}

import type { CSSProperties, ReactNode } from "react";
import type {
  Locale,
  DayProps,
  DatePickerSize,
  DateRangePreset,
  CaptionLayout,
  CalendarMonth,
  UseDatePickerOptions,
  UseDateRangePickerOptions,
  UseDateTimePickerOptions,
  UseDateRangeTimePickerOptions,
  TimeConfig,
  TimePeriod,
} from "react-date-range-picker-headless";
// ── Render prop context types ──

export interface TriggerRenderProps {
  displayValue: string;
  placeholder: string;
  hasValue: boolean;
  isOpen: boolean;
  onToggle: () => void;
  onClear: () => void;
  locale: Locale;
  triggerRef: (node: HTMLElement | null) => void;
}

export interface HeaderRenderProps {
  month: Date;
  formattedMonthYear: string;
  onPrevMonth: () => void;
  onNextMonth: () => void;
  locale: Locale;
  captionLayout: CaptionLayout;
  years: number[];
  months: number[];
  onYearSelect: (year: number) => void;
  onMonthSelect: (month: number) => void;
}

export interface WeekdayRowRenderProps {
  weekdays: string[];
}

export interface DayCellRenderProps extends DayProps {
  id: string;
  onClick: () => void;
  onMouseEnter?: () => void;
  onMouseLeave?: () => void;
}

export interface FooterRenderProps {
  canConfirm: boolean;
  hasValue: boolean;
  onConfirm: () => void;
  onCancel: () => void;
  onClear: () => void;
  locale: Locale;
}

export interface TimeSectionRenderProps {
  displayValue: string;
  label: string;
  timeConfig: Required<TimeConfig>;
  hour: number;
  minute: number;
  second: number;
  period: TimePeriod;
}

export interface PresetsBarRenderProps {
  presets: DateRangePreset[];
  activePresetIndex: number;
  onPresetClick: (preset: DateRangePreset) => void;
}

// ── Shared visual/render props ──

export interface RenderProps {
  renderTrigger?: (props: TriggerRenderProps) => ReactNode;
  renderHeader?: (props: HeaderRenderProps) => ReactNode;
  renderWeekdayRow?: (props: WeekdayRowRenderProps) => ReactNode;
  renderDayCell?: (props: DayCellRenderProps) => ReactNode;
  renderFooter?: (props: FooterRenderProps) => ReactNode;
  renderTimeSection?: (props: TimeSectionRenderProps) => ReactNode;
  renderPresetsBar?: (props: PresetsBarRenderProps) => ReactNode;
}

export interface VisualProps {
  className?: string;
  style?: CSSProperties;
  inline?: boolean;
  hideHeader?: boolean;
  hideFooter?: boolean;
  hideWeekdays?: boolean;
}

// ── Form integration props ──

export interface FormNameProps {
  name?: string;
}

export interface RangeFormNameProps extends FormNameProps {
  endName?: string;
}

// ── Public component props ──

export interface DatePickerProps extends UseDatePickerOptions, VisualProps, RenderProps, FormNameProps {}

export interface DateRangePickerProps extends UseDateRangePickerOptions, VisualProps, RenderProps, RangeFormNameProps {}

export interface DateTimePickerProps extends UseDateTimePickerOptions, VisualProps, RenderProps, FormNameProps {}

export interface DateRangeTimePickerProps
  extends UseDateRangeTimePickerOptions, VisualProps, Omit<RenderProps, "renderTimeSection">, RangeFormNameProps {
  renderTimeSection?: (props: RangeTimeSectionRenderProps) => ReactNode;
}

import type { UseStandaloneTimePickerOptions } from "react-date-range-picker-headless";

export interface TimePickerPanelProps extends UseStandaloneTimePickerOptions {
  size?: DatePickerSize;
  className?: string;
  style?: CSSProperties;
  hideFooter?: boolean;
  renderFooter?: (props: FooterRenderProps) => ReactNode;
}

// ── Internal CalendarGrid props ──

export interface CalendarGridProps {
  calendar: CalendarMonth;
  locale: Locale;
  focusedDate?: Date | null;
  getDayProps: (date: Date, referenceMonth?: Date) => DayProps;
  onDateClick: (date: Date) => void;
  onDateHover?: (date: Date | null) => void;
  showTitle?: boolean;
  hideWeekdays?: boolean;
  captionLayout?: CaptionLayout;
  years?: number[];
  monthOptions?: number[];
  onYearSelect?: (year: number, calendarIndex?: number) => void;
  onMonthSelect?: (month: number, calendarIndex?: number) => void;
  calendarIndex?: number;
  renderWeekdayRow?: (props: WeekdayRowRenderProps) => ReactNode;
  renderDayCell?: (props: DayCellRenderProps) => ReactNode;
}

// ── Internal TimePanelInternal props ──

export interface TimePanelInternalProps {
  hour: number;
  minute: number;
  second: number;
  period: TimePeriod;
  onHourChange: (h: number) => void;
  onMinuteChange: (m: number) => void;
  onSecondChange: (s: number) => void;
  onPeriodChange: (p: TimePeriod) => void;
  timeConfig: Required<TimeConfig>;
}

import type { RefObject } from "react";
import { useTimePicker, padNumber, to12Hour } from "react-date-range-picker-headless";
import type { TimePanelInternalProps } from "./types";
import { cn } from "./utils";

export function TimePanelInternal({
  hour,
  minute,
  second,
  period,
  onHourChange,
  onMinuteChange,
  onSecondChange,
  onPeriodChange,
  timeConfig,
}: TimePanelInternalProps) {
  const displayHour = timeConfig.hourFormat === "12" ? to12Hour(hour).hour : hour;

  const tp = useTimePicker({
    hour: displayHour,
    minute,
    second,
    period,
    onHourChange,
    onMinuteChange,
    onSecondChange,
    onPeriodChange,
    precision: timeConfig.precision,
    hourFormat: timeConfig.hourFormat,
    minuteStep: timeConfig.minuteStep,
    secondStep: timeConfig.secondStep,
    itemHeight: timeConfig.itemHeight,
  });

  const handleKeyDown = (
    e: React.KeyboardEvent,
    items: number[],
    selectedValue: number,
    onItemClick: (v: number) => void,
  ) => {
    const currentIndex = items.indexOf(selectedValue);
    if (currentIndex < 0) return;

    const findNext = (from: number, dir: 1 | -1): number => {
      let idx = from;
      do {
        idx = dir === 1
          ? (idx < items.length - 1 ? idx + 1 : 0)
          : (idx > 0 ? idx - 1 : items.length - 1);
      } while (items[idx] === -1 && idx !== from);
      return idx;
    };

    if (e.key === "ArrowUp") {
      e.preventDefault();
      const next = findNext(currentIndex, -1);
      if (items[next] !== -1) onItemClick(items[next]);
    } else if (e.key === "ArrowDown") {
      e.preventDefault();
      const next = findNext(currentIndex, 1);
      if (items[next] !== -1) onItemClick(items[next]);
    } else if (e.key === "Home") {
      e.preventDefault();
      const first = items.findIndex((v) => v !== -1);
      if (first >= 0) onItemClick(items[first]);
    } else if (e.key === "End") {
      e.preventDefault();
      for (let i = items.length - 1; i >= 0; i--) {
        if (items[i] !== -1) { onItemClick(items[i]); break; }
      }
    } else if (e.key === "Enter" || e.key === " ") {
      e.preventDefault();
    }
  };

  const renderColumn = (
    ref: RefObject<HTMLDivElement | null>,
    items: number[],
    selectedValue: number,
    onItemClick: (v: number) => void,
    onScroll: () => void,
    slug: string,
    ariaLabel?: string,
  ) => (
    <div
      ref={ref}
      className="flex-1 h-[160px] overflow-y-auto [scrollbar-width:none] [scroll-snap-type:y_mandatory] [&::-webkit-scrollbar]:hidden"
      onScroll={onScroll}
      role="listbox"
      aria-label={ariaLabel}
      tabIndex={0}
      aria-activedescendant={`time-${slug}-${selectedValue}`}
      onKeyDown={(e) => handleKeyDown(e, items, selectedValue, onItemClick)}
    >
      {items.map((item, i) =>
        item === -1 ? (
          <div key={`pad-${slug}-${i}`} className="h-8 shrink-0" aria-hidden="true" />
        ) : (
          <div
            id={`time-${slug}-${item}`}
            key={`${slug}-${item}`}
            role="option"
            aria-selected={item === selectedValue}
            aria-label={ariaLabel ? `${padNumber(item)} ${ariaLabel.toLowerCase()}` : undefined}
            data-slot="time-item"
            className={cn(
              "h-8 flex items-center justify-center cursor-pointer text-sm text-muted-foreground [scroll-snap-align:center] transition-colors select-none hover:text-foreground",
              item === selectedValue && "text-foreground font-semibold",
            )}
            onClick={() => onItemClick(item)}
          >
            {padNumber(item)}
          </div>
        ),
      )}
    </div>
  );

  return (
    <div
      className="relative inline-flex items-center justify-center min-w-[120px] h-[176px]"
      data-slot="time-panel"
    >
      <div className="absolute left-1 right-1 h-8 rounded-md bg-primary/8 pointer-events-none" />
      <div className="relative flex items-center w-full h-full">
        {renderColumn(
          tp.hourListRef,
          tp.hours,
          displayHour,
          tp.handleHourClick,
          tp.handleHourScroll,
          "hour",
          "Hours",
        )}

        {tp.showMinutes && (
          <>
            <div className="text-sm font-semibold text-foreground w-3 text-center shrink-0">:</div>
            {renderColumn(
              tp.minuteListRef,
              tp.minutes,
              minute,
              tp.handleMinuteClick,
              tp.handleMinuteScroll,
              "minute",
              "Minutes",
            )}
          </>
        )}

        {tp.showSeconds && (
          <>
            <div className="text-sm font-semibold text-foreground w-3 text-center shrink-0">:</div>
            {renderColumn(
              tp.secondListRef,
              tp.seconds,
              second,
              tp.handleSecondClick,
              tp.handleSecondScroll,
              "second",
              "Seconds",
            )}
          </>
        )}

        {tp.is12Hour && (
          <button
            type="button"
            className="h-8 flex items-center justify-center cursor-pointer text-sm text-foreground font-semibold hover:bg-accent hover:text-accent-foreground rounded-md"
            onClick={tp.handlePeriodToggle}
            aria-label={`Toggle AM/PM, current: ${period}`}
            aria-pressed={period === "PM"}
          >
            {period}
          </button>
        )}
      </div>
    </div>
  );
}
